INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '空力の基礎理論/三次元翼', '翼面積が同じで翼幅を2倍にした場合のアスペクト比（縦横比）で正しいものはどれか。', '["2倍になる。", "1／2になる。", "4倍になる。", "1／4になる。"]'::jsonb, 3, 'アスペクト比(AR)は「翼幅の2乗 ÷ 翼面積 (b^2 / S)」で計算されます。翼面積(S)が同じで、翼幅(b)を2倍にすると、2の2乗でアスペクト比は「4倍」になります。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 1, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','アスペクト比','計算'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '空力の基礎理論/力学の基礎', '層流と乱流の特性で正しいものはどれか。', '["層流は乱流よりも摩擦抵抗が大きい。", "乱流は層流よりも境界層が厚い。", "乱流中では流速は規則的に変化しているが、層流中では流速の変化は不規則である。", "層流はエネルギーが豊富で剥離しにくいが、乱流はエネルギーが少なく剥離しやすい。"]'::jsonb, 2, '乱流は空気が混ざり合いながら流れるため、滑らかに流れる層流に比べて摩擦抵抗が大きく、境界層が「厚く」なります。しかし乱流は周囲からエネルギーを取り込むため、層流よりも「剥離（失速）しにくい」という長所があります。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 2, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','層流と乱流','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '空力の基礎理論/二次元翼', '迎え角が失速角以上になった場合の説明で正しいものはどれか。', '["翼に当たる空気の流速が急激に減る。", "翼の上面の気流が剥離し、同時に抗力が急増、揚力が急減する。", "翼の周囲の気流が乱れて上下面の圧力が急減する。", "翼の下面に渦が発生し、振動が生ずる。"]'::jsonb, 2, '迎え角が大きくなり限界（失速角）を超えると、翼の上面を流れる空気が表面に沿って流れられなくなり（剥離）、揚力が急激に減少すると同時に、抵抗（抗力）が急激に増加します。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 3, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','失速','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '空力の基礎理論/全機の空力特性', '翼の平面形の説明（a）～（d）の正誤の組み合わせについて正しいものはどれか。 (a) 矩形翼は翼端失速の傾向が小さい。 (b) 先細（テーパ）翼はテーパを強くすると翼端失速を起こしやすい。 (c) 楕円翼の失速は翼全体から見ると不均一に発生する。 (d) 後退翼では翼端失速は起こらない。', '["(a)正 (b)誤 (c)正 (d)誤", "(a)正 (b)正 (c)誤 (d)誤", "(a)誤 (b)正 (c)誤 (d)正", "(a)誤 (b)誤 (c)正 (d)正"]'::jsonb, 2, '(a)矩形翼は付け根から失速するため翼端失速しにくく安全です。(b)テーパ翼は先を細くするほど翼端失速しやすくなります。(c)楕円翼は翼全体で「均一（同時）」に失速するため誤りです。(d)後退翼は翼端失速が「起こりやすい」ため誤りです。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 4, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','翼の平面形','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '空力の基礎理論/全機の空力特性', '幾何学的ねじり下げの説明で誤りはどれか。', '["翼端に近づくほど有効迎え角が小さくなっている。", "翼端部の取付角が翼根部より小さい。", "翼の外観はねじったように見える。", "翼端部は翼根部より失速しにくい翼型が採用されている。"]'::jsonb, 4, '「幾何学的ねじり下げ」は、翼の物理的な取付角を翼端にいくほど小さくねじることを言います。選択肢(4)のように、翼の断面形状（翼型）そのものを変えて失速を防ぐ手法は「空力的ねじり下げ」と呼びます。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 5, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','ねじり下げ','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '性能と耐空性/設計強度', '耐空性審査要領の速度の定義で誤りはどれか。', '["V_NEとは超過禁止速度をいう。", "V_NOとは構造上の最大巡航速度をいう。", "V_Aとは設計運動速度をいう。", "V_Dとは最大突風に対する設計速度をいう。"]'::jsonb, 4, 'V_D (Design Diving Speed) は「設計急降下速度」のことです。最大突風に対する設計速度は V_B (Design Speed for Maximum Gust) と呼ばれます。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 6, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','V速度','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '航空機の構造/荷重と強度', '制限荷重の説明で正しいものはどれか。', '["運用中予想される最大荷重で、この荷重までは構造は有害な残留変形を生じることはない。", "構造設計時の荷重基準で、この荷重までは構造は破壊しないが有害な残留変形を生じることがある。", "水平直線飛行時に主翼にかかる荷重で、この荷重をもとに最大荷重を決める。", "荷重試験において実際に構造が破壊した荷重で、この荷重を超えると構造はすぐに破壊する可能性が強い。"]'::jsonb, 1, '制限荷重（リミット・ロード）は、実際の運用でかかる可能性のある最大の荷重であり、この力を受けても機体に有害な「永久変形」が残らないように設計されます。（破壊を許容しない限界は終極荷重といいます）', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 7, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','制限荷重','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '性能と耐空性/離着陸性能', '耐空類別「飛行機普通N」の離陸距離の定義で正しいものはどれか。', '["離陸及び離陸面から浮揚するまでの必要距離", "離陸及び離陸面から10.7m（35ft）の高度に達するまでの必要距離", "離陸及び離陸面から15m（50ft）の高度に達するまでの必要距離", "離陸及び離陸面から製造者が決めた高度に達するまでの必要距離"]'::jsonb, 3, '小型機（普通N類など）の離陸距離は、静止状態から滑走を始め、空中に浮揚して高度50フィート（15m）に達するまでの水平距離と定義されています。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 8, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 10.0, 1, 'verified', ARRAY['CPL','航空工学','離陸距離','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '性能と耐空性/飛行性能', '最良上昇率速度について説明した文章の下線部（a）～（d）のうち、正しいものはいくつあるか。 「巡航形態において上昇率が最大となる速度は、(a)利用馬力が他の形態よりも小さいために、余剰馬力が大きくなるので(b)高い上昇率を得ることができる。この速度を最良上昇率速度といい、これを一般に(c)Vxで表す。最良上昇率速度は(d)機体重量により変化する。」', '["1つ", "2つ", "3つ", "4つ"]'::jsonb, 2, '正しいのは(b)と(d)の2つです。(a)「利用馬力」ではなく、飛行に必要な「必要馬力」が最小になるため余剰馬力が大きくなります。(c)最良上昇率速度はVxではなく「Vy」です（Vxは最良上昇角速度）。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 9, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','最良上昇率速度','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '航空機の構造/機体の構造', 'フェール・セーフ構造の基本方式として正しい組み合わせはどれか。（※問題不成立の可能性があるため学習用に用語を補正）', '["ある部材が破壊したとき、その部材の代わりに予備の部材が荷重を受け持つ構造をバックアップ構造という。", "基本部材に硬い補強材を当てた構造をロード・ドロッピング構造という。", "数多くの部材からなり、それぞれの部材が分担して受け持つ構造をセーフ・ライフ構造という。", "1個の大きな部材の代わりに2個以上の小さな部材を結合する構造をサンドイッチ構造という。"]'::jsonb, 1, 'フェールセーフには、予備を持たせる「バックアップ構造（冗長構造）」や、多数で分担する「マルチプル・ロード・パス構造」、板を重ねる「ダブル構造（ビルトアップ構造）」などがあります。（選択肢1は本来の正しい説明の組み合わせです）', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 10, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','フェール・セーフ構造','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '着陸装置/降着装置の形式', 'シミー・ダンパの役目で正しいものはどれか。', '["車輪の上下方向の振動を防止する。", "車輪の首振り運動を減衰、防止する。", "着陸接地時の衝撃を吸収する。", "内部圧力の上昇によるタイヤの破裂（バースト）を防止する。"]'::jsonb, 2, 'シミー・ダンパは、前輪（ノーズギア）が地上滑走中や着陸時に左右に激しく首を振る（シミー現象）のを油圧等で抑え込み、安定させるための装置です。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 11, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','シミー・ダンパ','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '燃料供給系統/燃料供給系統', 'ベーパ・ロックの防止方法（a）～（d）のうち、正しいものはいくつあるか。 (a) 燃料の配管を熱源から遠ざける。 (b) 燃料の配管に鋭い曲折部を作らない。 (c) 揮発性の高い燃料を使用する。 (d) 燃料を加圧状態に保つ。', '["1つ", "2つ", "3つ", "4つ"]'::jsonb, 3, '正しいのは(a)(b)(d)の3つです。ベーパ・ロックは燃料が気化して配管内に泡ができ、流れを阻害する現象です。(c)揮発性が高い（気化しやすい）燃料を使うと、逆にベーパ・ロックが起こりやすくなります。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 12, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','ベーパ・ロック','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '油圧系統/油圧の原理', '油圧系統の特徴について誤りはどれか。', '["装置重量の割に大きな力と動力が得られ、制御しやすい。", "作動または操作させる場合、応答速度は速いが、運動方向の制御は難しい。", "運動速度の制御範囲が広く、無段変速ができる。", "過負荷に対しては安全性が高いが、パイプなどの接続個所で作動液が漏れやすい。"]'::jsonb, 2, '油圧システムは、バルブの切り替えなどで流体の向きを変えるだけで簡単に運動方向を制御できるため、「運動方向の制御は容易である」が正しく、「難しい」とする記述は誤りです。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 13, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','油圧系統の特徴','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '着氷', '防除氷の方法（a）～（d）のうち、正しいものはいくつあるか。 (a) 高温の空気を用いた表面の加熱 (b) 電熱による加熱 (c) 膨張ブーツによる着氷した氷の破砕 (d) アルコール噴射', '["1つ", "2つ", "3つ", "4つ"]'::jsonb, 4, 'すべて実際の航空機で使用されている正しい防除氷の方法です。エンジンの熱風（ブリードエア）や電熱ヒーター、ゴムを膨らませて氷を割るブーツ、アルコール等の防氷液などが適材適所で使われます。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 14, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','防除氷','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', 'エア・データー表示計器/高度計', '気圧高度計で気圧高度（Pressure Altitude）を知るための方法で正しいものはどれか。', '["気圧補正目盛を、標準大気の海面上の気圧（29.92inHg）に合わせる。", "気圧補正目盛を、その時のその場所の気圧に合わせる。", "気圧補正目盛を、目的空港の気圧に合わせる。", "気圧補正目盛を、高度計の指示が0になるように合わせる。"]'::jsonb, 1, '「気圧高度（Pressure Altitude）」とは、高度計の気圧設定窓（コールスマン・ウィンドウ）を標準大気圧である「29.92 inHg (1013.2 hPa)」に合わせたときに高度計が示す値のことです。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 15, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','気圧高度','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', 'ピストン・エンジン/点火系統と始動系統', 'ピストン発動機の点火系統を構成する部品のうち、マグネトの役割で正しいものはどれか。', '["コイルで発生した低圧電流を機体のバッテリ回路に供給する。", "電流をディストリビュータから点火栓へ導く。", "点火系統からの無線障害を防止する。", "それぞれのシリンダの点火栓に送るため断続的に高電圧を発生させる。"]'::jsonb, 4, 'マグネトは、エンジン自体の回転を利用して内部のコイルで高電圧を発生させる独立した発電機です。バッテリーが上がってもエンジンが止まらないよう、スパークプラグ（点火栓）に高電圧を送る役割を持ちます。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 16, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','マグネト','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '航法計器/無線航法計器', 'VORに関する説明（a）～（d）のうち、正しいものはいくつあるか。 (a) 基準位相信号と可変位相信号の位相差を測定することによりラジアルを表示する。 (b) 周波数はVHF帯である。 (c) 旋回誤差に注意する必要がある。 (d) VOR局からの見通し線以上の高度でなければ受信できない。', '["1つ", "2つ", "3つ", "4つ"]'::jsonb, 3, '正しいのは(a)(b)(d)の3つです。(c)旋回時に指示がズレる「旋回誤差（ディップエラー）」は、磁気コンパスやADF（無指向性無線標識）に特有の誤差であり、VORにはありません。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 17, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','VOR','理論'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', 'エア・データー表示計器/高度計', '気圧高度計（空盒計器）の誤差に関する説明（a）～（d）のうち、正しいものはいくつあるか。 (a) 目盛誤差とは大気圧と高度の関係が非直線形であることにより、修正しても残ってしまう誤差をいう。 (b) 温度誤差とは高度計を構成するすべての部分の温度変化による膨張、収縮によって生じる誤差をいう。 (c) 弾性誤差とは空盒の弾性体の特性により生じる種々の誤差をいう。 (d) 機械的誤差とは可動部分、連結、歯車などのガタ、隙間、摩擦等により生じる誤差をいう。', '["1つ", "2つ", "3つ", "4つ"]'::jsonb, 4, 'すべて正しい記述です。気圧高度計という計器そのものが持つ誤差（器差）には、これらの4種類が含まれます。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 18, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 6.0, 1, 'verified', ARRAY['CPL','航空工学','高度計誤差','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '重量、重心位置一般/重量の定義', '航空機の自重に含まれるもの（a）～（d）のうち、正しいものはいくつあるか。 (a) 使用不能燃料 (b) 滑油 (c) 動力装置 (d) 固定バラスト', '["1つ", "2つ", "3つ", "4つ"]'::jsonb, 4, '航空機の自重（Empty Weight）には、機体やエンジン（動力装置）のほか、タンクから吸い出せない「使用不能燃料」、規定量の「滑油（エンジンオイル）」、「固定バラスト（重り）」などがすべて含まれます。', '{"sources": [{"type": "cpl_master_csv", "year": 2017, "month": 5, "question_no": 19, "subject_code": "AD", "file": "_master_AD.csv"}], "weight": 2.0, "originality": "official"}'::jsonb, 3, 8.0, 1, 'verified', ARRAY['CPL','航空工学','自重','暗記'], 'CPL') ON CONFLICT (main_subject, sub_subject, question_text, correct_answer) DO NOTHING
INSERT INTO unified_cpl_questions (main_subject, sub_subject, question_text, options, correct_answer, explanation, source_documents, difficulty_level, importance_score, appearance_frequency, verification_status, tags, exam_type) VALUES ('航空工学', '重量、重心位置の測定と算出/重量、重心位置の算出', '総重量3,500kgの飛行機の重心位置はどれか。 前輪の重量：500kg、主車輪（左右合計）：3,000kg 基準線から前輪までの距離：前輪は基準線の後方30cm 前輪から主車輪までの距離：300cm', '["基準線後方 196 cm", "基準線後方 220 cm", "基準線後方 261 cm", "基準線後方 285 cm"]'::jsonb, 3, 'モーメントを計算します。基準線から前輪のアームは30cm、主車輪のアームは30+300=330cmです。
